Rule.Source:
  import java.util.ArrayList; 
  import java.util.Iterator; 
  import java.util.List;
  import sailpoint.object.Identity; 
  import sailpoint.object.QueryOptions; 
  import sailpoint.object.Filter; 
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Bundle;
  import sailpoint.object.Link;
  import sailpoint.object.EmailFileAttachment;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.EmailOptions;
  import java.util.HashMap;
  import java.util.Map;
  import java.text.SimpleDateFormat;
import java.util.Date;
  String emailTemplateName = "Ascension-EmailTemplate-TerminatedIdentitiesActiveAccounts";
  Log log = LogFactory.getLog("com.test.rule"); 
  
  StringBuilder dataBuilder = null;
	dataBuilder = new StringBuilder();
	dataBuilder.append("\"Identity Name\"|\"First Name\"|\"Last Name\"|\"Display Name\"|\"CTR EXP Date\"|\"Manager\"|\"Application\"|\"Account\"|\"Email\"\n");
  
  QueryOptions qo = new QueryOptions(); 
  qo.addFilter(Filter.and(Filter.eq("inactive",true))); 
  qo.setOrderBy("firstname"); 
  //qo.setResultLimit(1000);
  String actionList;
  String actionListForRoles = "";
  String listOfUsers ="";
  String noAppsForUser = "";
  List emailTo = new ArrayList();
  emailTo.add("rajesh.saka@ascension.org");
  ArrayList colsToRead = new ArrayList(); 
  colsToRead.add("name");
  colsToRead.add("firstname"); 
  colsToRead.add("lastname"); 
  colsToRead.add("email"); 
  colsToRead.add("id");
  colsToRead.add("ctrexpDt");
  colsToRead.add("manager");
  Map args  = new HashMap();
  args.put("emailTemplate", emailTemplateName);
  Iterator it = context.search(Identity.class, qo, colsToRead); 
  List rows = new ArrayList();
  while ( (null != it) && (it.hasNext()) ) { 
    
    Object [] thisRecord = it.next(); 
    String n = (String) thisRecord[0];
    String fn = (String) thisRecord[1]; 
    String ln = (String) thisRecord[2]; 
    String em = (String) thisRecord[3]; 
    String nid = (String) thisRecord[4];
    Identity identity = context.getObjectById(Identity.class,nid);
    args.put("identityName",identity.getName());
    args.put("firstName", identity.getAttribute("firstname"));
    args.put("lastName", identity.getAttribute("lastname"));
    args.put("email",identity.getAttribute("email"));
    args.put("displayName",identity.getDisplayName());
    log.debug("name:["  +n+  "]+  firstName:[" + fn + "] + lastName:[" + ln + "] email:[" + em + "]   ID["   +nid+    "]"); 
    log.debug("IDENTITY:  "+identity.getDisplayName());
    if(null != n || "" != n){
      List links = identity.getLinks();
      List roles = identity.getAssignedRoles();
      
      if(null != links){
        
        for(Link link: links){
          
          if(link.getApplicationName() != null @and !link.isDisabled()){
            
            if(link.getApplication().getType().equals("Active Directory - Direct")){
              
                String records = identity.getName()+"|"+identity.getFirstname()+"|"+identity.getLastname()+"|"+identity.getDisplayName()+"|"+identity.getAttribute("ctrexpDt")+"|"+identity.getManager()+"|"+link.getApplicationName()+"|"+link.getDisplayName()+"|"+identity.getEmail();
              	rows.add(records);
              
            }
           
            
          }
          else{
            //Do Nothing
            noAppsForUser = "No Active Accounts";  //  : "+identity.getName();
            //uncomment above and comment below, below code is for testing only
            
          }   
        }
        //--args.put("actionList",actionList);
        if(noAppsForUser != "No Active Accounts"){
          if("" == listOfUsers  ||  null == listOfUsers){
            listOfUsers = n;
          }else{
            listOfUsers = listOfUsers+","+n;
          }                                           
        }
      }
    }                                           
    
  } 
  if(rows.size()>0){
    int i =0;
    String recordRows = null;
    for (String rec: rows) {
      dataBuilder.append(rec);
      dataBuilder.append("\n");
      i++;
		}
recordRows = dataBuilder.toString().replaceAll("null", "");

     
    //Setup Email To Send
	SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HHmmss", Locale.getDefault());
	String currentDateandTime = sdf.format(new Date());
    Map mailargs = new HashMap();;
    
	  String fileName = emailTemplateName+"-"+currentDateandTime+".csv";
    EmailTemplate template = context.getObjectByName(EmailTemplate.class, emailTemplateName);
    EmailOptions mailopts = null;
    EmailFileAttachment attachment = null;
	
	
	Map toAddrMap = new HashMap();
	toAddrMap.add("cam.weyhrich@ascension.org");
	toAddrMap.add("amy.goulet@ascension.org");
	toAddrMap.add("rajesh.saka@ascension.org");
	toAddrMap.add("joshua.pendleton@ascension.org");
    mailopts = new EmailOptions(toAddrMap, mailargs);
    attachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, recordRows.getBytes("UTF-8"));
    mailopts.addAttachment(attachment);
    context.sendEmailNotification(template, mailopts);
  }
  sailpoint.tools.Util.flushIterator(it); 
  return rows;
